import React, { useState } from 'react';
import { useAuth } from '../contexts/AuthContext';
import NeuralBackground from '../components/NeuralBackground';

export default function LoginPage() {
  const { signIn } = useAuth();
  const [email, setEmail]     = useState('');
  const [sent, setSent]       = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError]     = useState('');

  async function handleSubmit(e) {
    e.preventDefault();
    if (!email.trim()) { setError('Please enter your email address.'); return; }
    setLoading(true);
    setError('');
    try {
      await signIn(email.trim());
      setSent(true);
    } catch (err) {
      setError(err.message || 'Failed to send magic link. Please try again.');
    } finally {
      setLoading(false);
    }
  }

  return (
    <div style={{
      minHeight: '100vh', background: '#1a1a2e', display: 'flex',
      alignItems: 'center', justifyContent: 'center', padding: 24, position: 'relative', overflow: 'hidden',
    }}>
      <NeuralBackground />

      <div style={{
        position: 'relative', zIndex: 1, width: '100%', maxWidth: 400,
        background: '#252542', border: '1px solid #3d3d6b', borderRadius: 16, padding: '36px 32px',
        boxShadow: '0 8px 40px rgba(0,0,0,.4)',
      }}>
        {/* Logo */}
        <div style={{ textAlign: 'center', marginBottom: 28 }}>
          <div style={{ fontSize: 36, marginBottom: 10 }}>🧠</div>
          <div style={{ fontFamily: "'DM Mono', monospace", fontSize: 20, fontWeight: 500, color: '#f0f0ff', marginBottom: 6 }}>
            NeuroInsight
          </div>
          <div style={{ fontSize: 13, color: '#94a3b8' }}>
            fMRI & wearable mental wellbeing analysis
          </div>
        </div>

        {sent ? (
          <div style={{ textAlign: 'center' }}>
            <div style={{ fontSize: 32, marginBottom: 14 }}>📬</div>
            <div style={{ fontSize: 16, fontWeight: 600, color: '#f0f0ff', marginBottom: 8 }}>
              Check your email
            </div>
            <div style={{ fontSize: 13, color: '#94a3b8', lineHeight: 1.6, marginBottom: 20 }}>
              We sent a login link to <strong style={{ color: '#a78bfa' }}>{email}</strong>.
              Click it to sign in — the link expires in 1 hour.
            </div>
            <button
              type="button"
              onClick={() => { setSent(false); setEmail(''); }}
              style={{ fontSize: 13, color: '#94a3b8', background: 'none', border: 'none', cursor: 'pointer', textDecoration: 'underline' }}
            >
              Use a different email
            </button>
          </div>
        ) : (
          <form onSubmit={handleSubmit}>
            <div style={{ marginBottom: 20 }}>
              <label style={{ display: 'block', fontSize: 12, color: '#94a3b8', marginBottom: 6 }}>
                Email address
              </label>
              <input
                type="email"
                value={email}
                onChange={e => setEmail(e.target.value)}
                placeholder="you@example.com"
                autoFocus
                style={{
                  width: '100%', padding: '10px 12px', borderRadius: 8,
                  border: '1px solid #3d3d6b', background: '#1a1a2e',
                  color: '#f0f0ff', fontSize: 14, outline: 'none', boxSizing: 'border-box',
                  transition: 'border-color .15s',
                }}
                onFocus={e => e.target.style.borderColor = '#8b5cf6'}
                onBlur={e => e.target.style.borderColor = '#3d3d6b'}
              />
            </div>

            {error && (
              <div style={{
                padding: '10px 12px', borderRadius: 8, marginBottom: 16,
                background: 'rgba(248,81,73,.1)', border: '1px solid rgba(248,81,73,.3)',
                fontSize: 13, color: '#fca5a5',
              }}>
                {error}
              </div>
            )}

            <button
              type="submit"
              disabled={loading}
              style={{
                width: '100%', padding: '11px 0', borderRadius: 8, border: 'none',
                background: loading ? '#4c3880' : '#8b5cf6', color: '#fff',
                fontSize: 14, fontWeight: 600, cursor: loading ? 'not-allowed' : 'pointer',
                transition: 'background .15s',
              }}
            >
              {loading ? 'Sending…' : 'Send login link →'}
            </button>

            <div style={{ textAlign: 'center', marginTop: 16, fontSize: 12, color: '#64748b', lineHeight: 1.5 }}>
              No password needed — we'll email you a secure one-click link.
            </div>
          </form>
        )}

        <div style={{
          marginTop: 24, paddingTop: 18, borderTop: '1px solid #3d3d6b',
          fontSize: 11, color: '#64748b', textAlign: 'center', lineHeight: 1.5,
        }}>
          Research use only · Not a clinical diagnostic tool
        </div>
      </div>
    </div>
  );
}
